const APP_VERSION='16';
const {stages,templates,stageGroups:defaultStageGroups,projectTypes:defaultProjectTypes}=window.JP_DATA;
const STORE='jp_gestor_obras_v16';
const FLOW=['Abierta','En proceso','Corregida','Verificada'];
const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const ico=n=>`<svg aria-hidden="true"><use href="#i-${n}"/></svg>`;
const esc=(v='')=>String(v).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));
const SB_CONFIG=window.JP_SUPABASE_CONFIG;
const sb=window.supabase.createClient(SB_CONFIG.url,SB_CONFIG.publishableKey,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}});
let state=load(), route={view:'home'}, visit=null, detail=null, calendarDate=new Date(), calendarSelected=null;
let authReady=false,currentSession=null,currentProfile=null,authMessage='',syncing=false,lastSync=null,workspaceError='',managementLoading=false,syncState='saved',syncMessage='Todo guardado';

let appReloading=false,lastVersionCheck=0;

async function registerUpdateManager(){
  if(!('serviceWorker' in navigator)||!location.protocol.startsWith('http'))return;
  try{
    const registration=await navigator.serviceWorker.register('./service-worker.js',{updateViaCache:'none'});
    navigator.serviceWorker.addEventListener('controllerchange',()=>{
      if(appReloading)return;
      appReloading=true;
      window.location.reload();
    });
    await registration.update();
    if(registration.waiting)registration.waiting.postMessage({type:'SKIP_WAITING'});
  }catch(error){
    console.warn('No se pudo verificar la actualización de la app.',error);
  }
}

async function clearAppShellCache(){
  if(!('caches' in window))return;
  const keys=await caches.keys();
  await Promise.all(keys.filter(key=>key.startsWith('jp-gestor-obras-')).map(key=>caches.delete(key)));
}

async function forceReloadApp(){
  if(appReloading)return;
  appReloading=true;
  setSyncState('saving','Recargando aplicación…');
  try{
    if('serviceWorker' in navigator){
      const registration=await navigator.serviceWorker.getRegistration();
      if(registration){
        await registration.update();
        if(registration.waiting)registration.waiting.postMessage({type:'SKIP_WAITING'});
      }
    }
    await clearAppShellCache();
  }catch(error){
    console.warn('La caché no pudo limpiarse completamente.',error);
  }
  const url=new URL(window.location.href);
  url.searchParams.set('_jp_refresh',Date.now().toString());
  window.location.replace(url.toString());
}

async function checkForCodeUpdate(manual=false){
  if(!navigator.onLine){
    if(manual)toast('Sin conexión. No se puede buscar una actualización.');
    return;
  }
  const now=Date.now();
  if(!manual&&now-lastVersionCheck<60000)return;
  lastVersionCheck=now;

  if(manual)toast('Buscando actualización…');

  try{
    const response=await fetch(`./version.json?_=${now}`,{cache:'no-store'});
    if(!response.ok)throw new Error('No se pudo leer la versión publicada.');
    const remote=await response.json();

    const registration='serviceWorker' in navigator
      ? await navigator.serviceWorker.getRegistration()
      : null;

    if(registration){
      await registration.update();
      if(registration.waiting){
        registration.waiting.postMessage({type:'SKIP_WAITING'});
        return;
      }
    }

    if(String(remote.version)!==APP_VERSION||manual){
      await forceReloadApp();
    }
  }catch(error){
    if(manual){
      await forceReloadApp();
    }else{
      console.warn('No se pudo comprobar la versión publicada.',error);
    }
  }
}

function cleanRefreshParameter(){
  const url=new URL(window.location.href);
  if(!url.searchParams.has('_jp_refresh'))return;
  url.searchParams.delete('_jp_refresh');
  history.replaceState(null,'',url.pathname+(url.searchParams.toString()?`?${url.searchParams}`:'')+url.hash);
}

function seed(){return{user:{id:'',name:'',role:'architect'},projects:[],checks:{},visitResults:{},issues:[],visits:[],plannedVisits:[],projectTasks:[],projectTypes:[...defaultProjectTypes],stageGroups:[...defaultStageGroups],activeVisit:null}}
function cleanupLegacyStorage(){
  [
    'jp_gestor_obras_v11',
    'jp_gestor_obras_v12',
    'jp_gestor_obras_v13',
    'jp_gestor_obras_v14',
    'jp_gestor_obras_v15',
    'jp_control_obra_v2',
    'jp_gestor_obras_v10'
  ].forEach(k=>localStorage.removeItem(k));
}
function load(){cleanupLegacyStorage();try{const x=JSON.parse(localStorage.getItem(STORE));if(x&&typeof x==='object'){x.projects=x.projects||[];x.visits=x.visits||[];x.plannedVisits=x.plannedVisits||[];x.issues=x.issues||[];x.checks=x.checks||{};x.visitResults=x.visitResults||{};x.projectTasks=x.projectTasks||[];x.projectTypes=x.projectTypes||[...defaultProjectTypes];x.stageGroups=x.stageGroups||[...defaultStageGroups];x.user=x.user||{id:'',name:'',role:'architect'};return x}}catch(e){}return seed()}
function save(){localStorage.setItem(STORE,JSON.stringify(state))}
function project(id){return state.projects.find(p=>p.id===id)}
function stage(id){return stages.find(s=>s.id===id)}
function key(pid,sid,sector,iid){return [pid,sid,sector,iid].join('|')}
function getCheck(pid,sid,sector,iid){return state.checks[key(pid,sid,sector,iid)]||{status:'pending',note:'',updatedAt:null,contactId:null,dueDate:null,visitId:null}}
function setCheck(pid,sid,sector,iid,patch){state.checks[key(pid,sid,sector,iid)]={...getCheck(pid,sid,sector,iid),...patch,updatedAt:new Date().toISOString()};save()}
function visitKey(visitId,sector,itemId){return`${visitId}|${sector}|${itemId}`}
function getVisitResult(visitId,sector,itemId){return state.visitResults[visitKey(visitId,sector,itemId)]||{status:'pending',note:'',updatedAt:null,contactId:null,dueDate:null,visitId,sector}}
function effectiveVisitResult(visitId,pid,sid,sector,itemId){const visitResult=state.visitResults[visitKey(visitId,sector,itemId)],current=getCheck(pid,sid,sector,itemId);if(!visitResult)return current;if(!current.updatedAt)return visitResult;if(!visitResult.updatedAt)return current;return new Date(current.updatedAt)>new Date(visitResult.updatedAt)?current:visitResult}
function setVisitResult(visitId,sector,itemId,patch){state.visitResults[visitKey(visitId,sector,itemId)]={...getVisitResult(visitId,sector,itemId),...patch,visitId,sector,updatedAt:new Date().toISOString()};save()}
function fmt(v,time=false){if(!v)return'Sin chequeos';const d=new Date(v);return d.toLocaleDateString('es-UY',time?{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}:{day:'2-digit',month:'short',year:'numeric'})}
function statsProject(p){let total=0,reviewed=0,done=0,obs=0,bad=0,critical=0,last=null;for(const s of stages.filter(x=>p.enabledStages.includes(x.id)))for(const sec of p.sectors)for(const it of taskItems(p,s)){total++;const c=getCheck(p.id,s.id,sec,it.id);if(c.status!=='pending')reviewed++;if(c.status==='ok')done++;if(c.status==='obs')obs++;if(c.status==='bad')bad++;if(it.priority==='Crítica'&&c.status!=='ok')critical++;if(c.updatedAt&&(!last||c.updatedAt>last))last=c.updatedAt}return{total,reviewed,done,obs,bad,critical,last}}
function statsStage(p,s,sector=null,visitId=null){const secs=sector?[sector]:p.sectors;let total=0,reviewed=0,done=0,obs=0,bad=0,last=null;for(const sec of secs)for(const it of taskItems(p,s)){total++;const c=visitId?effectiveVisitResult(visitId,p.id,s.id,sec,it.id):getCheck(p.id,s.id,sec,it.id);if(c.status!=='pending')reviewed++;if(c.status==='ok')done++;if(c.status==='obs')obs++;if(c.status==='bad')bad++;if(c.updatedAt&&(!last||c.updatedAt>last))last=c.updatedAt}return{total,reviewed,done,obs,bad,last}}


function projectTaskRows(projectId,stageId){return(state.projectTasks||[]).filter(x=>x.projectId===projectId&&x.stageId===stageId)}
function taskItems(p,s){
  if(!p||!s)return[];
  const rows=projectTaskRows(p.id,s.id);
  const overrides=new Map(rows.filter(x=>x.sourceItemId).map(x=>[x.sourceItemId,x]));
  const blank=p.template==='Sin plantilla';
  const base=blank?[]:s.items.map((item,index)=>{
    const override=overrides.get(item.id);
    if(override&&override.active===false)return null;
    return{
      ...item,
      ...(override?{
        task:override.task,
        future:override.future,
        priority:override.priority,
        blocks:override.blocks,
        sortOrder:override.sortOrder,
        customRecordId:override.id,
        sourceItemId:item.id,
        overridden:true
      }:{
        sortOrder:(index+1)*10,
        customRecordId:null,
        sourceItemId:item.id,
        overridden:false
      }),
      id:item.id,
      isCustom:false
    }
  }).filter(Boolean);
  const custom=rows.filter(x=>!x.sourceItemId&&x.active!==false).map(x=>({
    id:x.itemKey,
    task:x.task,
    future:x.future||'',
    priority:x.priority||'Media',
    blocks:!!x.blocks,
    sortOrder:x.sortOrder||999,
    customRecordId:x.id,
    sourceItemId:null,
    overridden:false,
    isCustom:true
  }));
  return[...base,...custom].sort((a,b)=>(a.sortOrder||0)-(b.sortOrder||0)||a.task.localeCompare(b.task,'es'));
}
function taskById(p,s,itemId){return taskItems(p,s).find(x=>x.id===itemId)}
function canManageProjectTasks(p){return!!p&&['owner','admin'].includes(p.projectRole)}

function isGeneralSector(name){return String(name||'').trim().toLowerCase()==='general'}
function projectTypesList(){return(state.projectTypes||defaultProjectTypes).filter(x=>x.active!==false).sort((a,b)=>a.name.localeCompare(b.name,'es'))}
function stageGroupsList(){return(state.stageGroups||defaultStageGroups).filter(x=>x.active!==false).sort((a,b)=>(a.sortOrder||0)-(b.sortOrder||0)||a.name.localeCompare(b.name,'es'))}
function projectTypeByName(name){return projectTypesList().find(x=>x.name===name)||projectTypesList()[0]||defaultProjectTypes[0]}
function stagesForGroup(group,p=null){return(group.stageIds||[]).map(stage).filter(Boolean).filter(s=>!p||p.enabledStages.includes(s.id))}
function ungroupedStages(p=null){const assigned=new Set(stageGroupsList().flatMap(g=>g.stageIds||[]));return stages.filter(s=>!assigned.has(s.id)&&(!p||p.enabledStages.includes(s.id)))}
function groupedStageOptions(p,selected=''){let html='';stageGroupsList().forEach((g,index)=>{const list=stagesForGroup(g,p);if(list.length)html+=`<optgroup label="Etapa ${index+1}: ${esc(g.name)}">${list.map(s=>`<option value="${s.id}" ${s.id===selected?'selected':''}>${esc(s.name)}</option>`).join('')}</optgroup>`});const other=ungroupedStages(p);if(other.length)html+=`<optgroup label="Otras etapas">${other.map(s=>`<option value="${s.id}" ${s.id===selected?'selected':''}>${esc(s.name)}</option>`).join('')}</optgroup>`;return html}
function groupedStageSections(p){let html='';stageGroupsList().forEach((g,index)=>{const list=stagesForGroup(g,p);if(!list.length)return;let done=0,total=0;list.forEach(s=>{const st=statsStage(p,s);done+=st.done;total+=st.total});html+=`<section class="stage-group-card"><div class="stage-group-head"><div><span>ETAPA ${index+1}</span><h3>${esc(g.name)}</h3></div><b>${done}/${total}</b></div><div class="list">${list.map((s,i)=>stageRow(p,s,`${index+1}.${i+1}`)).join('')}</div></section>`});const other=ungroupedStages(p);if(other.length)html+=`<section class="stage-group-card"><div class="stage-group-head"><div><span>ETAPAS</span><h3>Sin categoría</h3></div></div><div class="list">${other.map((s,i)=>stageRow(p,s,`—`)).join('')}</div></section>`;return html||empty('No hay etapas habilitadas.')}
function groupedStageCheckboxes(enabled=[]){let html='';stageGroupsList().forEach((g,index)=>{const list=stagesForGroup(g);if(!list.length)return;html+=`<section class="config-group"><div class="config-group-title">Etapa ${index+1}: ${esc(g.name)}</div>${list.map(s=>`<label class="row"><input type="checkbox" value="${s.id}" ${enabled.includes(s.id)?'checked':''}><div class="row-main"><div class="row-title">${esc(s.name)}</div></div></label>`).join('')}</section>`});const other=ungroupedStages();if(other.length)html+=`<section class="config-group"><div class="config-group-title">Sin categoría</div>${other.map(s=>`<label class="row"><input type="checkbox" value="${s.id}" ${enabled.includes(s.id)?'checked':''}><div class="row-main"><div class="row-title">${esc(s.name)}</div></div></label>`).join('')}</section>`;return html}

function openIssues(pid){return state.issues.filter(i=>i.projectId===pid&&!['Corregida','Verificada'].includes(i.lifecycle))}
function openObservations(pid){return openIssues(pid).filter(i=>i.status==='obs')}
function openNonConformities(pid){return openIssues(pid).filter(i=>i.status==='bad')}
function toast(t){const x=$('#toast');x.textContent=t;x.classList.add('show');setTimeout(()=>x.classList.remove('show'),1700)}
function go(r){route=r;render();scrollTo(0,0)}
function nav(name){$$('#bottomNav button').forEach(b=>b.classList.toggle('active',b.dataset.nav===name))}
function setSyncState(stateValue,message){syncState=stateValue;syncMessage=message||({saving:'Guardando…',saved:'Todo guardado',offline:'Sin conexión',error:'Error al guardar'})[stateValue]||'';renderSyncIndicator()}
function renderSyncIndicator(){const el=$('#syncIndicator');if(!el)return;el.className=`sync-indicator ${syncState}`;el.innerHTML=`<span></span>${esc(syncMessage)}`}
function render(){const a=$('#app'),top=$('.topbar'),bottom=$('#bottomNav');if(!authReady){top.style.display='none';bottom.style.display='none';a.innerHTML=loadingView();return}if(!currentSession){top.style.display='none';bottom.style.display='none';a.innerHTML=loginView();bindLogin();return}top.style.display='flex';bottom.style.display=route.view==='visit'?'none':'grid';nav(['project','visit','project-admin'].includes(route.view)?'projects':route.view);if(route.view==='home')a.innerHTML=home();if(route.view==='projects')a.innerHTML=projects();if(route.view==='project')a.innerHTML=projectView(project(route.projectId));if(route.view==='project-admin')a.innerHTML=projectAdminView(project(route.projectId));if(route.view==='visit')a.innerHTML=visitView();if(route.view==='search')a.innerHTML=searchView();if(route.view==='visits')a.innerHTML=visitsView();renderSyncIndicator();bind()}
function loadingView(){return`<section class="auth-shell"><div class="auth-card"><div class="auth-logo">JP</div><div class="auth-kicker">JP</div><h1>Conectando…</h1><p>Verificando la sesión y el acceso a las obras.</p></div></section>`}
function loginView(){return`<section class="auth-shell"><form class="auth-card" id="loginForm"><div class="auth-logo">JP</div><div class="auth-kicker">GESTOR DE OBRAS</div><h1>Iniciar sesión</h1><p>Acceso interno del estudio.</p>${authMessage?`<div class="auth-error">${esc(authMessage)}</div>`:''}<div class="field"><label>Correo</label><input id="loginEmail" type="email" autocomplete="email" required></div><div class="field"><label>Contraseña</label><input id="loginPassword" type="password" autocomplete="current-password" required></div><button class="solid auth-submit" id="loginButton" type="submit">Ingresar</button></form></section>`}
function bindLogin(){const form=$('#loginForm');if(!form)return;form.onsubmit=async e=>{e.preventDefault();const button=$('#loginButton');button.disabled=true;button.textContent='Ingresando…';authMessage='';const{error}=await sb.auth.signInWithPassword({email:$('#loginEmail').value.trim(),password:$('#loginPassword').value});if(error){authMessage=loginErrorText(error);button.disabled=false;render()}}}
function loginErrorText(error){const m=(error?.message||'').toLowerCase();if(m.includes('invalid login'))return'Correo o contraseña incorrectos.';if(m.includes('email not confirmed'))return'El correo todavía no fue confirmado.';return error?.message||'No se pudo iniciar sesión.'}
function home(){const active=state.projects.filter(p=>p.status!=='Finalizado'),finished=state.projects.filter(p=>p.status==='Finalizado'),crit=state.issues.filter(i=>i.lifecycle!=='Verificada'&&(i.status==='bad'||i.priority==='Crítica')).slice(0,5),recent=[...state.visits].filter(v=>v.status==='closed').sort((a,b)=>b.startedAt.localeCompare(a.startedAt)).slice(0,4),drafts=state.visits.filter(v=>v.status==='draft').sort((a,b)=>b.startedAt.localeCompare(a.startedAt));return`<section class="hero compact-hero"><div class="kicker">DIRECCIÓN DE OBRA</div><h1><strong>GESTOR DE OBRAS</strong></h1><p>actualización continua de estado de obras</p><div class="hero-actions"><button class="solid" data-action="new-project">${ico('plus')} Nuevo proyecto</button></div></section>${drafts.length?`<section class="section"><div class="section-head"><h2>Borradores abiertos</h2><button data-action="all-visits">Ver todos</button></div><div class="list">${drafts.slice(0,3).map(visitRow).join('')}</div></section>`:''}<section class="section"><div class="section-head"><h2>Proyectos activos</h2><button data-action="all-projects">Ver todos</button></div><div class="list project-grid">${active.map(projectRow).join('')||empty('No hay proyectos activos.')}</div></section>${finished.length?`<section class="section finished-section"><div class="section-head"><h2>Proyectos finalizados</h2><button data-action="all-projects">Ver todos</button></div><div class="list project-grid">${finished.slice(0,4).map(projectRow).join('')}</div></section>`:''}<section class="section"><div class="section-head"><h2>Pendientes críticos</h2><button data-action="find-critical">Buscar</button></div><div class="list">${crit.map(issueRow).join('')||empty('No hay pendientes críticos abiertos.')}</div></section><section class="section"><div class="section-head"><h2>Visitas recientes</h2><button data-action="all-visits">Historial</button></div><div class="list">${recent.map(visitRow).join('')||empty('Todavía no hay visitas registradas.')}</div></section>`}
function activeVisit(){const v=state.activeVisit,p=project(v.projectId),s=stage(v.stageId);return`<section class="section"><button class="row" data-action="resume"><span class="dot yellow"></span><div class="row-main"><div class="row-title">Continuar visita</div><div class="row-sub">${esc(p.name)} · ${esc(s.name)} · ${esc(v.sector)}</div></div>${ico('next')}</button></section>`}
function projectRow(p){const st=statsProject(p),s=stage(p.currentStage),finished=p.status==='Finalizado';return`<button class="row project-row ${finished?'project-finished':''}" data-project="${p.id}"><div class="count-badge"><b>${st.done}</b><span>/${st.total}</span></div><div class="row-main"><div class="row-title">${esc(p.name)}</div><div class="row-sub">${esc(p.status)} · ${esc(s?.name||'Sin etapa')}</div><div class="row-meta">${finished?'<span class="pill green">Finalizado</span>':`<span class="urgent">${st.critical} críticos</span><span class="warning">${st.obs} observaciones</span>`}<span>${projectRoleLabel(p.projectRole)}</span></div></div>${ico('next')}</button>`}
function issueRow(i){const p=project(i.projectId);return`<button class="row" data-issue="${i.id}"><span class="dot ${i.status==='bad'?'red':'yellow'}"></span><div class="row-main"><div class="row-title">${esc(i.code)} · ${esc(i.title)}</div><div class="row-sub">${esc(p?.name||'')} · ${esc(i.sector)} · ${esc(i.lifecycle)}</div><div class="row-meta"><span>${esc(i.contactName||'Sin responsable')}</span><span>${i.dueDate?'Vence '+fmt(i.dueDate):'Sin fecha'}</span></div></div>${ico('next')}</button>`}
function visitRow(v){const p=project(v.projectId),s=stage(v.stageId),draft=v.status==='draft';return`<button class="row" data-visit="${v.id}"><span class="dot ${draft?'yellow':'green'}"></span><div class="row-main"><div class="row-title">${draft?'Borrador · ':''}${esc(p?.name||'Proyecto')} · ${esc(s?.name||'Etapa')}</div><div class="row-sub">${esc(v.sector)} · ${fmt(v.startedAt,true)}</div><div class="row-meta"><span>${ico('user')} ${esc(v.userName||state.user.name)}</span><span>${v.reviewed||0} revisados</span><span>${v.issues||0} observaciones</span></div></div>${ico('next')}</button>`}
function empty(t){return`<div class="empty">${esc(t)}</div>`}
function projects(){const active=state.projects.filter(p=>p.status!=='Finalizado'),finished=state.projects.filter(p=>p.status==='Finalizado');return`<div class="page-head"><div><h1>Proyectos</h1><p>${active.length} activos · ${finished.length} finalizados</p></div></div><div class="toolbar"><div class="searchbox">${ico('search')}<input id="projectSearch" placeholder="Buscar proyecto, cliente o ubicación"></div></div><section class="section" style="margin-top:8px"><div class="section-head"><h2>Activos</h2></div><div class="list project-grid" id="activeProjects">${active.map(projectRow).join('')||empty('No hay proyectos activos.')}</div></section><section class="section finished-section"><div class="section-head"><h2>Finalizados</h2></div><div class="list project-grid" id="finishedProjects">${finished.map(projectRow).join('')||empty('No hay proyectos finalizados.')}</div></section><button class="floating" data-action="new-project">${ico('plus')}</button>`}
function projectView(p){if(!p)return empty('Proyecto no encontrado.');const st=statsProject(p),current=stage(p.currentStage),observations=openObservations(p.id),nonConformities=openNonConformities(p.id),issues=[...observations,...nonConformities],canManage=['owner','admin'].includes(p.projectRole),finished=p.status==='Finalizado';return`<div class="page-head"><button class="back" data-action="back-projects">${ico('back')}</button><div><h1>${esc(p.name)}</h1><p>${esc(p.template)} · ${esc(p.status)}</p></div></div><section class="summary ${finished?'summary-finished':''}"><div class="summary-top"><div><h2>${esc(p.name)}</h2><p>Etapa actual: ${esc(current?.name||'Sin definir')} · Último chequeo: ${fmt(st.last,true)}</p></div>${canManage?`<button class="icon-btn" data-action="manage-project" aria-label="Administrar proyecto">${ico('settings')}</button>`:''}</div><div class="metrics"><div class="metric"><b>${st.done}/${st.total}</b><span>Conformes</span></div><div class="metric"><b>${st.critical}</b><span>Críticos</span></div><div class="metric"><b>${issues.length}</b><span>Pendientes</span></div></div><div class="hero-actions project-status-actions">${finished?'<span class="pill green project-complete-pill">Proyecto finalizado</span>':`<button class="solid" data-action="start-visit">${ico('plus')} Comenzar visita</button>`}<button class="project-issue-button observation" data-action="project-observations">${ico('alert')} Observaciones <b>${observations.length}</b></button><button class="project-issue-button nonconformity" data-action="project-nonconformities">${ico('alert')} No conformes <b>${nonConformities.length}</b></button></div>${canManage?`<button class="management-link" data-action="manage-project">Administrar datos, arquitectos y accesos ${ico('next')}</button>`:''}</section><section class="section"><div class="section-head"><h2>Etapas de obra</h2><div class="section-head-actions"><button data-action="edit-stages">Etapas</button>${canManage?'<button data-action="manage-tasks">Tareas</button>':''}</div></div>${p.template==='Sin plantilla'&&canManage?'<div class="blank-project-note">Proyecto sin plantilla: las tareas se cargan manualmente en cada etapa.</div>':''}${groupedStageSections(p)}</section>`}
function stageRow(p,s,n){const enabled=p.enabledStages.includes(s.id),st=statsStage(p,s);return`<button class="row ${enabled?'':'disabled'}" data-stage="${s.id}" ${enabled?'':'disabled'}><div class="stage-no">${esc(n)}</div><div class="row-main"><div class="row-title">${esc(s.name)}</div><div class="row-sub">${st.done}/${st.total} conformes · ${fmt(st.last,true)}</div></div><div class="stage-right"><b>${st.done}/${st.total}</b><small>${st.bad} no conformes</small></div>${ico('next')}</button>`}
function projectRoleLabel(role){return({owner:'Propietario',admin:'Administrador',architect:'Arquitecto',read_only:'Solo lectura'})[role]||'Miembro'}
function projectAdminView(p){if(!p)return empty('Proyecto no encontrado.');if(!['owner','admin'].includes(p.projectRole))return`<div class="page-head"><button class="back" data-action="back-project">${ico('back')}</button><div><h1>Administración</h1><p>Sin permisos de administración</p></div></div>${empty('Solo el propietario o un administrador del proyecto puede modificar integrantes y eliminar la obra.')}`;const members=p.members||[];return`<div class="page-head"><button class="back" data-action="back-project">${ico('back')}</button><div><h1>Administrar proyecto</h1><p>${esc(p.name)}</p></div></div><section class="admin-card"><div class="section-head"><h2>Datos principales</h2></div><div class="field"><label>Nombre del proyecto</label><input id="adminName" value="${esc(p.name)}"></div><div class="field"><label>Tipo de proyecto</label><select id="adminTemplate"><option ${p.template==='Sin plantilla'?'selected':''}>Sin plantilla</option>${projectTypesList().map(x=>`<option ${x.name===p.template?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div><div class="inline"><div class="field"><label>Cliente</label><input id="adminClient" value="${esc(p.client||'')}"></div><div class="field"><label>Ubicación</label><input id="adminLocation" value="${esc(p.location||'')}"></div></div><div class="inline"><div class="field"><label>Estado</label><select id="adminStatus">${['No iniciado','En ejecución','Detenido','Próximo a entrega','Finalizado'].map(x=>`<option ${x===p.status?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Etapa actual</label><select id="adminStage">${groupedStageOptions(p,p.currentStage)}</select></div></div><div class="field"><label>Sectores — uno por línea</label><textarea id="adminSectors">${esc(p.sectors.join('\n'))}</textarea></div><div class="field"><label>Contactos de obra — uno por línea</label><textarea id="adminContacts">${esc(p.contacts.map(c=>c.name).join('\n'))}</textarea></div><button class="solid full-button" data-action="save-project-admin">Guardar datos del proyecto</button></section><section class="section admin-card"><div class="section-head"><h2>Tareas de control</h2></div><p class="muted">Editá las tareas existentes o agregá controles exclusivos para este proyecto.</p><button class="ghost full-button" data-action="manage-tasks">${ico('settings')} Administrar tareas por etapa</button></section><section class="section admin-card"><div class="section-head"><h2>Arquitectos y accesos</h2><button data-action="reload-members">Actualizar</button></div><div class="member-list">${managementLoading?'<div class="empty">Cargando integrantes…</div>':members.map(m=>memberRow(p,m)).join('')||empty('No se pudieron cargar los integrantes.')}</div><div class="member-add"><div class="field"><label>Correo del arquitecto</label><input id="memberEmail" type="email" placeholder="arquitecto@estudio.com"></div><div class="field"><label>Permiso</label><select id="memberRole"><option value="architect">Arquitecto</option><option value="read_only">Solo lectura</option><option value="admin">Administrador</option></select></div><button class="ghost full-button" data-action="add-project-member">${ico('plus')} Agregar usuario existente</button><p class="muted">El correo debe corresponder a un usuario ya creado.</p></div></section><section class="section danger-zone"><h2>Zona de riesgo</h2><p>Eliminar el proyecto borra sus datos relacionados. Esta acción no se puede deshacer.</p><button class="danger full-button" data-action="delete-project-admin">Eliminar proyecto</button></section>`}
function memberRow(p,m){const self=m.user_id===currentSession.user.id,owner=m.member_role==='owner';return`<article class="member-row"><div class="member-avatar">${esc((m.full_name||m.email||'?').trim().charAt(0).toUpperCase())}</div><div class="row-main"><div class="row-title">${esc(m.full_name||m.email||'Usuario')}</div><div class="row-sub">${esc(m.email||'')} · ${projectRoleLabel(m.member_role)}</div></div>${owner?'<span class="pill green">Propietario</span>':self?'<span class="pill">Vos</span>':`<button class="tiny" data-member-menu="${m.user_id}">${ico('dots')}</button>`}</article>`}
async function openProjectAdmin(p){if(!p||!['owner','admin'].includes(p.projectRole))return toast('No tenés permisos para administrar este proyecto');route={view:'project-admin',projectId:p.id};managementLoading=true;render();try{await loadProjectMembers(p)}catch(error){workspaceError=dbErrorText(error);toast(workspaceError)}finally{managementLoading=false;render()}}
async function loadProjectMembers(p){const{data,error}=await sb.rpc('list_project_members',{p_project_id:p.id});if(error)throw error;p.members=data||[];save()}
async function saveProjectAdmin(p){const button=$('[data-action="save-project-admin"]'),name=$('#adminName').value.trim(),template=$('#adminTemplate').value,client=$('#adminClient').value.trim(),location=$('#adminLocation').value.trim(),status=$('#adminStatus').value,current_stage=$('#adminStage').value,sectors=$('#adminSectors').value.split('\n').map(x=>x.trim()).filter(Boolean),contactNames=$('#adminContacts').value.split('\n').map(x=>x.trim()).filter(Boolean);if(!name)return toast('El proyecto necesita un nombre');button.disabled=true;button.textContent='Guardando…';try{const{error}=await sb.from('projects').update({name,template,client,location,status,current_stage,updated_at:new Date().toISOString()}).eq('id',p.id);if(error)throw error;await syncProjectSectors(p,sectors.length?sectors:['General']);await syncProjectContacts(p,contactNames);await loadRemoteWorkspace();route={view:'project-admin',projectId:p.id};await loadProjectMembers(project(p.id));render();toast('Proyecto actualizado')}catch(error){button.disabled=false;button.textContent='Guardar datos del proyecto';toast(dbErrorText(error))}}
async function addProjectMember(p){const email=$('#memberEmail').value.trim().toLowerCase(),role=$('#memberRole').value;if(!email)return toast('Ingresá el correo del arquitecto');const button=$('[data-action="add-project-member"]');button.disabled=true;button.textContent='Agregando…';try{const{error}=await sb.rpc('add_project_member_by_email',{p_project_id:p.id,p_email:email,p_member_role:role});if(error)throw error;await loadProjectMembers(p);render();toast('Arquitecto agregado')}catch(error){button.disabled=false;button.textContent='Agregar usuario existente';toast(dbErrorText(error))}}
function memberMenu(p,userId){const m=(p.members||[]).find(x=>x.user_id===userId);if(!m)return;modal('Acceso al proyecto',`<div class="field"><label>Integrante</label><input value="${esc(m.full_name||m.email)}" disabled></div><div class="field"><label>Permiso</label><select id="editMemberRole"><option value="architect" ${m.member_role==='architect'?'selected':''}>Arquitecto</option><option value="read_only" ${m.member_role==='read_only'?'selected':''}>Solo lectura</option><option value="admin" ${m.member_role==='admin'?'selected':''}>Administrador</option></select></div>`,`<button class="danger" id="removeMember">Quitar</button><button class="ghost" data-close>Cancelar</button><button class="solid" id="saveMemberRole">Guardar</button>`);$('#saveMemberRole').onclick=async()=>{const{error}=await sb.rpc('set_project_member_role',{p_project_id:p.id,p_user_id:userId,p_member_role:$('#editMemberRole').value});if(error)return toast(dbErrorText(error));await loadProjectMembers(p);closeModal();render();toast('Permiso actualizado')};$('#removeMember').onclick=async()=>{if(!confirm(`¿Quitar a ${m.full_name||m.email} del proyecto?`))return;const{error}=await sb.rpc('remove_project_member',{p_project_id:p.id,p_user_id:userId});if(error)return toast(dbErrorText(error));await loadProjectMembers(p);closeModal();render();toast('Integrante eliminado')}}
async function deleteManagedProject(p){if(!confirm(`¿Eliminar definitivamente ${p.name}?`))return;const{error}=await sb.from('projects').delete().eq('id',p.id);if(error)return toast(dbErrorText(error));await loadRemoteWorkspace();go({view:'projects'});toast('Proyecto eliminado')}

function searchView(){return`<div class="page-head"><div><h1>Buscar</h1><p>Proyectos, controles, observaciones y responsables</p></div></div><div class="toolbar"><div class="searchbox">${ico('search')}<input id="globalSearch" autofocus placeholder="Ej.: impermeabilización, OBS-004, sanitario"></div></div><div id="searchResults" class="list">${empty('Ingresá un término de búsqueda.')}</div>`}
function visitsView(){const closed=[...state.visits].filter(v=>v.status==='closed').sort((a,b)=>b.startedAt.localeCompare(a.startedAt)),drafts=[...state.visits].filter(v=>v.status==='draft').sort((a,b)=>b.startedAt.localeCompare(a.startedAt)),planned=[...state.plannedVisits].filter(x=>x.status!=='cancelled').sort((a,b)=>plannedStamp(a).localeCompare(plannedStamp(b))),monthLabel=calendarDate.toLocaleDateString('es-UY',{month:'long',year:'numeric'});return`<div class="page-head"><div><h1>Visitas</h1><p>Calendario, borradores e historial</p></div><button class="icon-btn" data-action="schedule-visit">${ico('plus')}</button></div><section class="calendar-card"><div class="calendar-head"><button class="icon-btn" data-action="cal-prev">${ico('back')}</button><div><b>${monthLabel.charAt(0).toUpperCase()+monthLabel.slice(1)}</b><button data-action="cal-today">Hoy</button></div><button class="icon-btn" data-action="cal-next">${ico('next')}</button></div>${calendarGrid()}</section>${drafts.length?`<section class="section"><div class="section-head"><h2>Borradores</h2></div><div class="list">${drafts.map(visitRow).join('')}</div></section>`:''}<section class="section"><div class="section-head"><h2>${calendarSelected?'Agenda del '+fmtDay(calendarSelected):'Próximas visitas tentativas'}</h2><button data-action="schedule-visit">Programar</button></div><div class="list" id="plannedList">${plannedRows(planned)}</div></section><section class="section"><div class="section-head"><h2>Visitas realizadas</h2></div><div class="list">${closed.map(visitRow).join('')||empty('Todavía no hay visitas registradas.')}</div></section>`}

function dateKey(d){const y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0');return`${y}-${m}-${day}`}
function fmtDay(v){if(!v)return'';return new Date(v+'T12:00:00').toLocaleDateString('es-UY',{day:'2-digit',month:'long'})}
function plannedStamp(v){return`${v.date||'9999-12-31'}T${v.time||'23:59'}`}
function plannedStatus(v){if(v.status==='completed')return'completed';const now=new Date(),d=new Date(`${v.date}T${v.time||'12:00'}:00`);return d<now?'overdue':'planned'}
function monthEvents(){const y=calendarDate.getFullYear(),m=calendarDate.getMonth();return{done:state.visits.filter(v=>{const d=new Date(v.startedAt);return d.getFullYear()===y&&d.getMonth()===m}),planned:state.plannedVisits.filter(v=>{if(v.status==='cancelled')return false;const d=new Date((v.date||'')+'T12:00:00');return d.getFullYear()===y&&d.getMonth()===m})}}
function calendarGrid(){const y=calendarDate.getFullYear(),m=calendarDate.getMonth(),first=new Date(y,m,1),last=new Date(y,m+1,0),offset=(first.getDay()+6)%7,{done,planned}=monthEvents(),today=dateKey(new Date());let cells='';for(let i=0;i<offset;i++)cells+='<div class="calendar-day empty-day"></div>';for(let day=1;day<=last.getDate();day++){const d=new Date(y,m,day),key=dateKey(d),hasDone=done.some(v=>dateKey(new Date(v.startedAt))===key),plans=planned.filter(v=>v.date===key),hasPlanned=plans.some(v=>plannedStatus(v)==='planned'),hasOverdue=plans.some(v=>plannedStatus(v)==='overdue');cells+=`<button class="calendar-day ${key===today?'today':''} ${key===calendarSelected?'selected':''}" data-day="${key}"><span>${day}</span><i>${hasDone?'<b class="event-dot done"></b>':''}${hasPlanned?'<b class="event-dot planned"></b>':''}${hasOverdue?'<b class="event-dot overdue"></b>':''}</i></button>`}return`<div class="calendar-week"><span>L</span><span>M</span><span>M</span><span>J</span><span>V</span><span>S</span><span>D</span></div><div class="calendar-grid">${cells}</div><div class="calendar-legend"><span><i class="event-dot done"></i> Realizada</span><span><i class="event-dot planned"></i> Tentativa</span><span><i class="event-dot overdue"></i> Atrasada</span></div>`}
function plannedRows(list){let filtered=list;if(calendarSelected){const completed=state.visits.filter(v=>dateKey(new Date(v.startedAt))===calendarSelected);const scheduled=list.filter(v=>v.date===calendarSelected);return[...scheduled.map(plannedVisitRow),...completed.map(visitRow)].join('')||empty('No hay visitas para esta fecha.')}filtered=list.filter(v=>plannedStatus(v)!=='overdue').slice(0,8);const overdue=list.filter(v=>plannedStatus(v)==='overdue');return[...overdue.map(plannedVisitRow),...filtered.map(plannedVisitRow)].join('')||empty('No hay próximas visitas tentativas.')}
function plannedVisitRow(v){const p=project(v.projectId),s=stage(v.stageId),status=plannedStatus(v),label=status==='overdue'?'Atrasada':'Tentativa';return`<button class="row planned-row" data-planned="${v.id}"><span class="dot ${status==='overdue'?'red':'yellow'}"></span><div class="row-main"><div class="row-title">${esc(p?.name||'Proyecto')} · ${esc(s?.name||'Etapa por definir')}</div><div class="row-sub">${fmtDay(v.date)}${v.time?' · '+esc(v.time):''} · ${esc(v.sector||'Sector por definir')}</div><div class="row-meta"><span>${ico('user')} ${esc(v.assignee||state.user.name)}</span><span class="${status==='overdue'?'urgent':'warning'}">${label}</span></div></div>${ico('next')}</button>`}
function scheduleVisit(existing=null){const projectsOptions=state.projects.filter(p=>p.status!=='Finalizado').map(p=>`<option value="${p.id}" ${p.id===(existing?.projectId||'')?'selected':''}>${esc(p.name)}</option>`).join('');if(!projectsOptions)return toast('Primero creá un proyecto activo');const initialProject=project(existing?.projectId)||state.projects.find(p=>p.status!=='Finalizado');modal(existing?'Editar visita tentativa':'Programar visita tentativa',`<div class="field"><label>Proyecto</label><select id="svProject">${projectsOptions}</select></div><div class="inline"><div class="field"><label>Fecha tentativa</label><input id="svDate" type="date" value="${esc(existing?.date||calendarSelected||dateKey(new Date()))}"></div><div class="field"><label>Hora</label><input id="svTime" type="time" value="${esc(existing?.time||'09:00')}"></div></div><div class="field"><label>Etapa prevista</label><select id="svStage"></select></div><div class="field"><label>Sector previsto</label><select id="svSector"></select></div><div class="field"><label>Objetivo / controles previstos</label><textarea id="svNote" placeholder="Ej.: liberar armaduras antes del hormigonado">${esc(existing?.note||'')}</textarea></div>`,`<button class="ghost" data-close>Cancelar</button>${existing?'<button class="danger" id="deleteScheduled">Eliminar</button>':''}<button class="solid" id="saveScheduled">${existing?'Guardar':'Programar'}</button>`);const fill=()=>{const p=project($('#svProject').value)||initialProject;$('#svStage').innerHTML=groupedStageOptions(p,existing?.stageId||p.currentStage);$('#svSector').innerHTML=p.sectors.map(x=>`<option ${x===(existing?.sector||p.sectors[0])?'selected':''}>${esc(x)}</option>`).join('')};$('#svProject').onchange=fill;fill();$('#saveScheduled').onclick=async()=>{const payload={project_id:$('#svProject').value,planned_date:$('#svDate').value,planned_time:$('#svTime').value||null,stage_id:$('#svStage').value,sector_name:$('#svSector').value,assigned_user_id:currentSession.user.id,objective:$('#svNote').value.trim(),status:existing?.status||'planned',created_by:currentSession.user.id,updated_at:new Date().toISOString()};if(!payload.planned_date)return toast('Definí una fecha tentativa');setSyncState('saving');let result;if(existing)result=await sb.from('planned_visits').update(payload).eq('id',existing.id);else result=await sb.from('planned_visits').insert(payload);if(result.error){setSyncState('error',dbErrorText(result.error));return toast(dbErrorText(result.error))}await loadOperationalData();closeModal();render();setSyncState('saved');toast(existing?'Visita actualizada':'Visita programada')};if(existing)$('#deleteScheduled').onclick=async()=>{if(!confirm('¿Eliminar esta visita tentativa?'))return;setSyncState('saving');const{error}=await sb.from('planned_visits').delete().eq('id',existing.id);if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}await loadOperationalData();closeModal();render();setSyncState('saved');toast('Visita eliminada')}}
function plannedVisitModal(id){const v=state.plannedVisits.find(x=>x.id===id);if(!v)return;const p=project(v.projectId),s=stage(v.stageId);modal('Visita tentativa',`<div class="check-meta"><span class="pill ${plannedStatus(v)==='overdue'?'red':'yellow'}">${plannedStatus(v)==='overdue'?'Atrasada':'Tentativa'}</span></div><p style="line-height:1.5"><b>${esc(p?.name||'Proyecto')}</b><br>${fmtDay(v.date)}${v.time?' · '+esc(v.time):''}<br>${esc(s?.name||'Etapa')} · ${esc(v.sector||'Sector')}</p><div class="field"><label>Responsable</label><input value="${esc(v.assignee||state.user.name)}" disabled></div>${v.note?`<div class="future"><b>Objetivo previsto</b><br>${esc(v.note)}</div>`:''}`,`<button class="ghost" data-close>Cerrar</button><button class="ghost" id="editScheduled">Editar</button><button class="solid" id="startScheduled">Comenzar visita</button>`);$('#editScheduled').onclick=()=>{closeModal();scheduleVisit(v)};$('#startScheduled').onclick=async()=>{setSyncState('saving');const{data:id,error}=await sb.rpc('create_visit_draft',{p_project_id:v.projectId,p_stage_id:v.stageId,p_sector_name:v.sector,p_planned_visit_id:v.id});if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}await loadOperationalData();visit=state.visits.find(x=>x.id===id);state.activeVisit=visit;save();closeModal();setSyncState('saved');go({view:'visit'})}}

function visitView(){const v=visit||state.activeVisit;if(!v)return'';const p=project(v.projectId),s=stage(v.stageId),st=statsStage(p,s,v.sector,v.id),filter=v.filter||'all',q=(v.query||'').toLowerCase();let list=taskItems(p,s).filter(it=>{const c=effectiveVisitResult(v.id,p.id,s.id,v.sector,it.id);if(filter==='pending'&&c.status!=='pending')return false;if(filter==='critical'&&it.priority!=='Crítica')return false;if(filter==='issues'&&!['obs','bad'].includes(c.status))return false;return!q||it.task.toLowerCase().includes(q)||it.future.toLowerCase().includes(q)});return`<div class="visit-head"><div class="page-head"><button class="back" data-action="leave-visit">${ico('back')}</button><div><h1>${esc(s.name)}</h1><p>${esc(p.name)} · ${esc(v.sector)}</p></div></div><div class="visit-context">Borrador iniciado ${fmt(v.startedAt,true)} · ${esc(v.userName||state.user.name)}</div><div class="progress-count"><b>${st.done}/${st.total}</b><span>ítems conformes</span><small>${st.reviewed}/${st.total} revisados</small></div>${isGeneralSector(v.sector)?'<div class="general-hint">Desde General podés aprobar cada control en todos los sectores con el botón “Todos”.</div>':''}</div><div class="toolbar"><div class="searchbox">${ico('search')}<input id="checkSearch" value="${esc(v.query||'')}" placeholder="Buscar control"></div><button class="filter-btn">${ico('filter')}</button></div><div class="tabs">${tab('all','Todos',filter)}${tab('pending','Sin revisar',filter)}${tab('critical','Críticos',filter)}${tab('issues','Observaciones',filter)}</div><div class="check-list">${list.map(it=>checkRow(p,s,v,it)).join('')||empty('No hay controles con este filtro.')}</div><div class="visit-bottom-actions no-print"><button class="ghost" data-action="save-return">${ico('back')} Guardar borrador y volver</button><button class="solid" data-action="close-visit">${ico('check')} Cerrar visita</button><button class="ghost" data-action="export-pdf">${ico('file')} Exportar PDF</button></div>`}
function tab(id,label,current){return`<button class="tab ${id===current?'active':''}" data-filter="${id}">${label}</button>`}
function checkRow(p,s,v,it){const c=effectiveVisitResult(v.id,p.id,s.id,v.sector,it.id),statusClass=`status-${c.status}`,signal=c.status==='ok'?ico('check'):c.status==='obs'?'!':c.status==='bad'?'×':'';return`<article class="check ${statusClass} ${it.priority==='Crítica'?'critical':''}"><button class="checkmark signal-${c.status}" data-action="quick-ok" data-item="${it.id}" aria-label="Marcar conforme">${signal}</button><button class="check-content" data-action="open-check" data-item="${it.id}"><div class="check-title">${esc(it.task)}</div><div class="check-meta">${it.priority==='Crítica'?'<span class="pill red">Crítico</span>':''}${it.blocks?'<span class="pill">Bloquea avance</span>':''}${c.status==='pending'?'<span class="pill">Sin revisar</span>':''}${c.status==='ok'?'<span class="pill green">Conforme</span>':''}${c.status==='obs'?'<span class="pill yellow">Observación</span>':''}${c.status==='bad'?'<span class="pill red">No conforme</span>':''}${c.updatedAt?`<span class="pill">${fmt(c.updatedAt,true)}</span>`:''}</div></button>${isGeneralSector(v.sector)?`<div class="all-sector-actions"><button class="all-sector-button ok" data-action="quick-ok-all" data-item="${it.id}" title="Conforme en todos los sectores">Todos ✓</button><button class="all-sector-button bad" data-action="confirm-bad-all" data-item="${it.id}" title="No conforme en todos los sectores">Todos NC</button></div>`:''}<button class="tiny" data-action="open-check" data-item="${it.id}">${ico('next')}</button></article>`}
function bind(){$$('[data-project]').forEach(b=>b.onclick=()=>go({view:'project',projectId:b.dataset.project}));$$('[data-stage]').forEach(b=>b.onclick=()=>newVisit(route.projectId,b.dataset.stage));$$('[data-issue]').forEach(b=>b.onclick=()=>issueModal(b.dataset.issue));$$('[data-visit]').forEach(b=>b.onclick=()=>openVisit(b.dataset.visit));$$('[data-planned]').forEach(b=>b.onclick=()=>plannedVisitModal(b.dataset.planned));$$('[data-day]').forEach(b=>b.onclick=()=>{calendarSelected=calendarSelected===b.dataset.day?null:b.dataset.day;render()});$$('[data-filter]').forEach(b=>b.onclick=()=>{const v=visit||state.activeVisit;v.filter=b.dataset.filter;persist(v);render()});$$('[data-member-menu]').forEach(b=>b.onclick=()=>memberMenu(project(route.projectId),b.dataset.memberMenu));$$('[data-action]').forEach(b=>b.onclick=()=>action(b.dataset.action,b));const ps=$('#projectSearch');if(ps)ps.oninput=()=>$$('.project-row').forEach(r=>r.hidden=!r.innerText.toLowerCase().includes(ps.value.toLowerCase()));const gs=$('#globalSearch');if(gs)gs.oninput=()=>search(gs.value);const cs=$('#checkSearch');if(cs)cs.oninput=()=>{const v=visit||state.activeVisit;v.query=cs.value;persist(v);render()}}
function action(a,e){const p=project(route.projectId);if(a==='new-project')newProject();if(a==='all-projects'||a==='back-projects')go({view:'projects'});if(a==='back-project')go({view:'project',projectId:route.projectId});if(a==='all-visits')go({view:'visits'});if(a==='find-critical'){go({view:'search'});setTimeout(()=>{$('#globalSearch').value='OBS';search('OBS')},0)}if(a==='resume'){visit=state.activeVisit;go({view:'visit'})}if(a==='start-visit')newVisit(route.projectId);if(a==='project-menu'||a==='manage-project')openProjectAdmin(p);if(a==='save-project-admin')saveProjectAdmin(p);if(a==='add-project-member')addProjectMember(p);if(a==='reload-members'){managementLoading=true;render();loadProjectMembers(p).then(()=>toast('Integrantes actualizados')).catch(error=>toast(dbErrorText(error))).finally(()=>{managementLoading=false;render()})}if(a==='delete-project-admin')deleteManagedProject(p);if(a==='edit-stages')stageConfig(p);if(a==='manage-tasks')taskManager(p);if(a==='project-issues'||a==='project-observations')issuesModal(route.projectId,'obs');if(a==='project-nonconformities')issuesModal(route.projectId,'bad');if(a==='quick-ok')quickOk(e.dataset.item);if(a==='quick-ok-all')quickOkAll(e.dataset.item);if(a==='confirm-bad-all')confirmBadAll(e.dataset.item);if(a==='open-check')checkModal(e.dataset.item);if(a==='leave-visit'||a==='save-return')leaveVisit();if(a==='close-visit')closeCurrentVisit();if(a==='export-pdf')exportVisitPdf();if(a==='schedule-visit')scheduleVisit();if(a==='sync-now')refreshRemote();if(a==='cal-prev'){calendarDate=new Date(calendarDate.getFullYear(),calendarDate.getMonth()-1,1);calendarSelected=null;render()}if(a==='cal-next'){calendarDate=new Date(calendarDate.getFullYear(),calendarDate.getMonth()+1,1);calendarSelected=null;render()}if(a==='cal-today'){calendarDate=new Date();calendarSelected=dateKey(new Date());render()}}
function newVisit(pid,sid=null){const p=project(pid);if(p.status==='Finalizado')return toast('El proyecto está finalizado');modal('Nueva visita',`<div class="field"><label>Etapa</label><select id="vStage">${groupedStageOptions(p,sid||p.currentStage)}</select></div><div class="field"><label>Sector</label><select id="vSector">${p.sectors.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="muted">Se guardará como borrador desde el primer momento.</div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="beginVisit">Comenzar inspección</button>`);$('#beginVisit').onclick=async()=>{const selectedStage=stage($('#vStage').value);if(!taskItems(p,selectedStage).length)return toast('Esta etapa no tiene tareas. Agregalas antes de iniciar la visita.');setSyncState('saving');const{data:id,error}=await sb.rpc('create_visit_draft',{p_project_id:p.id,p_stage_id:$('#vStage').value,p_sector_name:$('#vSector').value,p_planned_visit_id:null});if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}await loadOperationalData();visit=state.visits.find(x=>x.id===id);state.activeVisit=visit;save();closeModal();setSyncState('saved');go({view:'visit'})}}
function persist(v){state.activeVisit=v;visit=v;save()}
async function quickOk(iid){const v=visit||state.activeVisit,p=project(v.projectId),s=stage(v.stageId),it=taskById(p,s,iid),previous=getVisitResult(v.id,v.sector,iid);setVisitResult(v.id,v.sector,iid,{status:'ok',note:'',dueDate:null,contactId:null});setCheck(v.projectId,v.stageId,v.sector,iid,{status:'ok',note:'',dueDate:null,contactId:null,visitId:v.id});render();setSyncState('saving');const{error}=await sb.rpc('save_visit_check_v2',{p_visit_id:v.id,p_check_item_id:iid,p_status:'ok',p_note:'',p_contact_id:null,p_due_date:null,p_title:it.task,p_priority:it.priority,p_lifecycle:'Verificada',p_sector_name:v.sector});if(error){setVisitResult(v.id,v.sector,iid,previous);setSyncState('error',dbErrorText(error));render();return toast(dbErrorText(error))}await loadOperationalData();setSyncState('saved');render();toast('Marcado conforme')}
async function quickOkAll(iid){const v=visit||state.activeVisit,p=project(v.projectId),s=stage(v.stageId),it=taskById(p,s,iid);if(!isGeneralSector(v.sector))return;setSyncState('saving');const{data:count,error}=await sb.rpc('mark_visit_check_ok_all_sectors',{p_visit_id:v.id,p_check_item_id:iid,p_title:it.task,p_priority:it.priority});if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}await loadOperationalData();setSyncState('saved');render();toast(`Conforme en ${count} sectores`)}

function confirmBadAll(iid){const v=visit||state.activeVisit,s=stage(v.stageId),it=taskById(p,s,iid);modal('No conforme en todos los sectores',`<p class="modal-warning">Esta acción marcará <b>${esc(it.task)}</b> como no conforme en cada sector del proyecto y generará una observación por sector.</p>`,`<button class="ghost" data-close>Cancelar</button><button class="danger" id="applyBadAll">Marcar todos en rojo</button>`);$('#applyBadAll').onclick=()=>{closeModal();quickBadAll(iid)}}
async function quickBadAll(iid){const v=visit||state.activeVisit,p=project(v.projectId),s=stage(v.stageId),it=taskById(p,s,iid);if(!isGeneralSector(v.sector))return;setSyncState('saving');const{data:count,error}=await sb.rpc('mark_visit_check_bad_all_sectors',{p_visit_id:v.id,p_check_item_id:iid,p_title:it.task,p_priority:it.priority});if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}await loadOperationalData();setSyncState('saved');render();toast(`No conforme en ${count} sectores`)}

function checkModal(iid){const v=visit||state.activeVisit,p=project(v.projectId),s=stage(v.stageId),it=taskById(p,s,iid),c=effectiveVisitResult(v.id,p.id,s.id,v.sector,iid);detail={v,p,s,it,c};modal(it.task,`<div class="check-meta" style="margin-bottom:11px">${it.priority==='Crítica'?'<span class="pill red">Crítico</span>':''}${it.blocks?'<span class="pill">Bloquea avance</span>':''}</div><div class="future"><b>Previsión futura</b><br>${esc(it.future)}</div><div class="field"><label>Resultado</label><div class="segments"><button class="segment green ${c.status==='ok'?'sel':''}" data-status="ok">Conforme</button><button class="segment yellow ${c.status==='obs'?'sel':''}" data-status="obs">Observación</button><button class="segment red ${c.status==='bad'?'sel':''}" data-status="bad">No conforme</button></div></div><div class="field"><label>Comentario</label><textarea id="note" placeholder="Describir ubicación, carencia y acción requerida...">${esc(c.note||'')}</textarea><div class="actions"><button id="dictate">${ico('mic')} Dictar</button></div></div><div id="issueFields" style="${['obs','bad'].includes(c.status)?'':'display:none'}"><div class="inline"><div class="field"><label>Responsable</label><select id="contact"><option value="">Sin asignar</option>${p.contacts.map(x=>`<option value="${x.id}" ${x.id===c.contactId?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div><div class="field"><label>Fecha límite</label><input id="due" type="date" value="${esc(c.dueDate||'')}"></div></div>${lifeHtml(p.id,s.id,v.sector,iid)}</div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="saveCheck">Guardar</button>`);$$('[data-status]').forEach(b=>b.onclick=()=>{$$('[data-status]').forEach(x=>x.classList.remove('sel'));b.classList.add('sel');$('#issueFields').style.display=['obs','bad'].includes(b.dataset.status)?'block':'none'});$$('[data-life]').forEach(b=>b.onclick=()=>{$$('[data-life]').forEach(x=>x.classList.remove('sel'));b.classList.add('sel')});$('#dictate').onclick=dictate;$('#saveCheck').onclick=saveCheckDetail}
function lifeHtml(pid,sid,sector,iid){const x=state.issues.find(i=>i.projectId===pid&&i.stageId===sid&&i.sector===sector&&i.itemId===iid&&!['Corregida','Verificada'].includes(i.lifecycle)),current=x?.lifecycle||'Abierta';return`<div class="field"><label>Estado de observación</label><div class="lifecycle">${FLOW.map(v=>`<button class="life ${v===current?'sel':''}" data-life="${v}">${v}</button>`).join('')}</div></div>`}
async function saveCheckDetail(){const{v,p,s,it}=detail,sel=$('[data-status].sel'),current=effectiveVisitResult(v.id,p.id,s.id,v.sector,it.id),status=sel?.dataset.status||current.status||'pending',note=$('#note').value.trim(),due=$('#due')?.value||null,contactId=$('#contact')?.value||null,lifecycle=$('[data-life].sel')?.dataset.life||'Abierta';setVisitResult(v.id,v.sector,it.id,{status,note,dueDate:due,contactId});setCheck(p.id,s.id,v.sector,it.id,{status,note,dueDate:due,contactId,visitId:v.id});closeModal();render();setSyncState('saving');const{error}=await sb.rpc('save_visit_check_v2',{p_visit_id:v.id,p_check_item_id:it.id,p_status:status,p_note:note,p_contact_id:contactId||null,p_due_date:due||null,p_title:it.task,p_priority:it.priority,p_lifecycle:lifecycle,p_sector_name:v.sector});if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}await loadOperationalData();setSyncState('saved');render();toast('Control guardado')}
function nextCode(pid){return`OBS-${String(state.issues.filter(i=>i.projectId===pid).length+1).padStart(4,'0')}`}
function dictate(){const SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR)return toast('El navegador no admite dictado');const r=new SR();r.lang='es-UY';r.onstart=()=>toast('Escuchando…');r.onresult=e=>$('#note').value=($('#note').value+' '+e.results[0][0].transcript).trim();r.onerror=()=>toast('No se pudo usar el micrófono');r.start()}
function leaveVisit(){const v=visit||state.activeVisit;state.activeVisit=v;save();go({view:'project',projectId:v.projectId});toast('Borrador guardado')}
function openVisit(id){const v=state.visits.find(x=>x.id===id);if(!v)return;if(v.status==='draft'){visit=v;state.activeVisit=v;save();go({view:'visit'})}else reportModal(id)}
async function closeCurrentVisit(){const v=visit||state.activeVisit;if(!v)return;setSyncState('saving');const{error}=await sb.rpc('close_visit',{p_visit_id:v.id});if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}state.activeVisit=null;visit=null;await loadOperationalData();setSyncState('saved');go({view:'project',projectId:v.projectId});toast('Visita cerrada')}
function exportVisitPdf(){const v=visit||state.activeVisit;if(v)reportModal(v.id)}
function finishVisit(){closeCurrentVisit()}
function reportModal(id){const v=state.visits.find(x=>x.id===id);if(!v)return;modal('Informe de visita',report(v),`<button class="ghost" data-close>Cerrar</button><button class="ghost" id="share">${ico('share')} Compartir</button><button class="solid" id="print">${ico('download')} Guardar PDF</button>`);$('#print').onclick=()=>print();$('#share').onclick=async()=>{const t=`Informe de visita · ${project(v.projectId).name} · ${stage(v.stageId).name} · ${fmt(v.startedAt,true)}`;if(navigator.share)await navigator.share({title:'Informe de visita',text:t});else{await navigator.clipboard.writeText(t);toast('Resumen copiado')}}}
function report(v){const p=project(v.projectId),s=stage(v.stageId),iss=state.issues.filter(i=>i.visitId===v.id),currentItems=taskItems(p,s),visitEntries=Object.values(state.visitResults).filter(x=>x.visitId===v.id&&x.sector===v.sector),resultMap=new Map(visitEntries.map(x=>[x.itemId,x])),known=new Set(currentItems.map(x=>x.id)),orphan=visitEntries.filter(x=>!known.has(x.itemId)).map((x,index)=>({id:x.itemId,task:x.title||x.itemId,future:'',priority:x.priority||'Media',blocks:false,sortOrder:100000+index})),items=[...currentItems,...orphan].sort((a,b)=>(a.sortOrder||0)-(b.sortOrder||0)),rows=items.map(it=>{const c=resultMap.get(it.id)||getVisitResult(v.id,v.sector,it.id),status=c.status||'pending',title=c.title||it.task;return`<tr class="report-status-${status}"><td>${esc(it.id)}</td><td>${esc(title)}</td><td><span class="report-state ${status}">${label(status)}</span></td><td>${esc(c.note||'')}</td></tr>`}).join('');return`<div class="report"><h1>JP · Informe de visita</h1><div class="report-meta"><b>Proyecto:</b> ${esc(p.name)}<br><b>Etapa:</b> ${esc(s.name)}<br><b>Sector:</b> ${esc(v.sector)}<br><b>Fecha:</b> ${fmt(v.startedAt,true)}<br><b>Arquitecto:</b> ${esc(v.userName||state.user.name)}</div><h2>Resumen</h2><div class="report-meta">${v.reviewed} controles revisados · ${v.ok} conformes · ${v.issues} observaciones/no conformidades</div><h2>Controles</h2><table><thead><tr><th>ID</th><th>Control</th><th>Estado</th><th>Comentario</th></tr></thead><tbody>${rows}</tbody></table><h2>Observaciones</h2>${iss.map(i=>`<div class="report-obs report-issue-${i.status}"><b>${esc(i.code)} · ${esc(i.title)}</b><p>${esc(i.note)}</p><p>Responsable: ${esc(i.contactName||'Sin asignar')} · Vence: ${i.dueDate?fmt(i.dueDate):'Sin fecha'} · Estado: ${esc(i.lifecycle)}</p></div>`).join('')||'<p>Sin observaciones.</p>'}<div style="margin-top:45px;border-top:1px solid #999;padding-top:7px;font-size:10px">Dirección de obra · JP</div></div>`}
function newProject(){const types=projectTypesList();modal('Nuevo proyecto',`<div class="field"><label>Nombre del proyecto</label><input id="npName" placeholder="Casa JJJ"></div><div class="field"><label>Forma de inicio</label><select id="npMode"><option value="template">Usar tipo de proyecto</option><option value="blank">Crear desde cero</option></select></div><div id="npTemplatePanel"><div class="field"><label>Tipo de proyecto</label><select id="npTemplate">${types.map(x=>`<option>${esc(x.name)}</option>`).join('')}</select></div></div><div id="npBlankPanel" style="display:none"><div class="field"><label>Sectores — uno por línea</label><textarea id="npBlankSectors">General</textarea></div><div class="field"><label>Etapas habilitadas</label><div id="npBlankStages">${groupedStageCheckboxes(stages.map(s=>s.id))}</div></div><div class="blank-project-note">El proyecto se crea sin tareas. Después se cargan manualmente desde “Tareas”.</div></div><div class="inline"><div class="field"><label>Cliente</label><input id="npClient"></div><div class="field"><label>Ubicación</label><input id="npLocation"></div></div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="createProject">Crear</button>`);const toggle=()=>{const blank=$('#npMode').value==='blank';$('#npTemplatePanel').style.display=blank?'none':'block';$('#npBlankPanel').style.display=blank?'block':'none'};$('#npMode').onchange=toggle;toggle();$('#createProject').onclick=async()=>{const name=$('#npName').value.trim();if(!name)return toast('Ingresá un nombre');const button=$('#createProject'),blank=$('#npMode').value==='blank';let template,enabledStages,sectorNames;if(blank){template='Sin plantilla';enabledStages=$$('input[type=checkbox]:checked',$('#npBlankStages')).map(x=>x.value);sectorNames=$('#npBlankSectors').value.split('\n').map(x=>x.trim()).filter(Boolean);if(!enabledStages.length)return toast('Habilitá al menos una etapa');if(!sectorNames.length)sectorNames=['General']}else{const type=projectTypeByName($('#npTemplate').value);template=type.name;enabledStages=type.enabledStageIds.length?type.enabledStageIds:stages.map(s=>s.id);sectorNames=type.sectorNames.length?type.sectorNames:['General']}button.disabled=true;button.textContent='Creando…';try{const{data:id,error}=await sb.rpc('create_project_bundle',{p_name:name,p_client:$('#npClient').value.trim(),p_location:$('#npLocation').value.trim(),p_template:template,p_status:'En ejecución',p_current_stage:enabledStages[0]||'preobra',p_enabled_stages:enabledStages,p_sector_names:sectorNames});if(error)throw error;await loadRemoteWorkspace();await loadOperationalData();closeModal();go({view:'project',projectId:id});toast(blank?'Proyecto vacío creado. Agregá las tareas por etapa.':'Proyecto creado y sincronizado')}catch(error){button.disabled=false;button.textContent='Crear';toast(dbErrorText(error))}}}
function projectMenu(p){openProjectAdmin(p)}
async function syncProjectSectors(p,names){const current=p.sectorRecords||[],keepIds=[];for(let n=0;n<names.length;n++){const name=names[n],old=current.find(x=>x.name===name);if(old){keepIds.push(old.id);const{error}=await sb.from('project_sectors').update({sort_order:n}).eq('id',old.id);if(error)throw error}else{const{data,error}=await sb.from('project_sectors').insert({project_id:p.id,name,sort_order:n}).select().single();if(error)throw error;keepIds.push(data.id)}}const remove=current.filter(x=>!keepIds.includes(x.id)).map(x=>x.id);if(remove.length){const{error}=await sb.from('project_sectors').delete().in('id',remove);if(error)throw error}}
async function syncProjectContacts(p,names){const current=p.contacts||[],keepIds=[];for(const name of names){const old=current.find(x=>x.name===name);if(old)keepIds.push(old.id);else{const{data,error}=await sb.from('contacts').insert({project_id:p.id,name}).select().single();if(error)throw error;keepIds.push(data.id)}}const remove=current.filter(x=>!keepIds.includes(x.id)).map(x=>x.id);if(remove.length){const{error}=await sb.from('contacts').delete().in('id',remove);if(error)throw error}}

function taskManager(p,selectedStageId=null){
  if(!canManageProjectTasks(p))return toast('Solo el propietario o administrador puede editar tareas');
  const sid=selectedStageId&&p.enabledStages.includes(selectedStageId)?selectedStageId:(p.currentStage||p.enabledStages[0]);
  const s=stage(sid),items=taskItems(p,s);
  modal('Tareas por etapa',`<div class="field"><label>Etapa</label><select id="taskStage">${groupedStageOptions(p,sid)}</select></div><div class="task-manager-summary">${items.length} tareas activas · ${esc(s?.name||'')}</div><div class="list task-manager-list">${items.map((it,index)=>`<button class="row" data-edit-task="${it.id}"><div class="stage-no">${index+1}</div><div class="row-main"><div class="row-title">${esc(it.task)}</div><div class="row-sub">${esc(it.priority)}${it.blocks?' · Bloquea avance':''}${it.isCustom?' · Personalizada':it.overridden?' · Editada':''}</div></div>${ico('next')}</button>`).join('')||empty('Esta etapa todavía no tiene tareas.')}</div>`,`<button class="ghost" data-close>Cerrar</button><button class="solid" id="addStageTask">${ico('plus')} Agregar tarea</button>`);
  $('#taskStage').onchange=()=>{const next=$('#taskStage').value;closeModal();taskManager(p,next)};
  $$('[data-edit-task]').forEach(b=>b.onclick=()=>{const item=taskById(p,s,b.dataset.editTask);closeModal();taskForm(p,s,item)});
  $('#addStageTask').onclick=()=>{closeModal();taskForm(p,s,null)};
}
function taskForm(p,s,item=null){
  const isEdit=!!item,recordId=item?.customRecordId||null,sourceItemId=item?.sourceItemId||null;
  const defaultOrder=item?.sortOrder||((taskItems(p,s).length+1)*10);
  modal(isEdit?'Editar tarea':'Nueva tarea',`<div class="field"><label>Tarea de control</label><textarea id="taskTitle" placeholder="Ej.: Verificar nivel y aplomado">${esc(item?.task||'')}</textarea></div><div class="field"><label>Previsión futura / criterio</label><textarea id="taskFuture" placeholder="Qué debe verificarse antes de avanzar">${esc(item?.future||'')}</textarea></div><div class="inline"><div class="field"><label>Prioridad</label><select id="taskPriority">${['Media','Alta','Crítica'].map(x=>`<option ${x===(item?.priority||'Media')?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Orden</label><input id="taskOrder" type="number" min="1" value="${defaultOrder}"></div></div><label class="password-toggle"><input id="taskBlocks" type="checkbox" ${item?.blocks?'checked':''}> Bloquea el avance de obra</label><div id="taskFormError" class="auth-error" style="display:none;margin-top:12px"></div>`,`<button class="ghost" id="cancelTaskForm">Cancelar</button>${recordId?`<button class="danger" id="removeTask">${sourceItemId?'Restaurar original':'Ocultar tarea'}</button>`:''}<button class="solid" id="saveTask">Guardar</button>`);
  $('#cancelTaskForm').onclick=()=>{closeModal();taskManager(p,s.id)};
  $('#saveTask').onclick=async()=>{
    const title=$('#taskTitle').value.trim(),future=$('#taskFuture').value.trim(),priority=$('#taskPriority').value,blocks=$('#taskBlocks').checked,sortOrder=Number($('#taskOrder').value)||10,errorBox=$('#taskFormError'),button=$('#saveTask');
    errorBox.style.display='none';
    if(!title)return toast('Ingresá la tarea');
    button.disabled=true;button.textContent='Guardando…';setSyncState('saving');
    const{error}=await sb.rpc('save_project_check_item',{
      p_project_id:p.id,
      p_stage_id:s.id,
      p_task:title,
      p_future:future,
      p_priority:priority,
      p_blocks:blocks,
      p_sort_order:sortOrder,
      p_id:recordId,
      p_item_key:item?.id||null,
      p_source_item_id:sourceItemId,
      p_is_active:true
    });
    if(error){errorBox.textContent=dbErrorText(error);errorBox.style.display='block';button.disabled=false;button.textContent='Guardar';setSyncState('error',dbErrorText(error));return}
    await loadOperationalData();closeModal();setSyncState('saved');taskManager(project(p.id),s.id);toast('Tarea guardada')
  };
  if(recordId)$('#removeTask').onclick=async()=>{
    const message=sourceItemId?'¿Restaurar la tarea original de la plantilla?':'¿Ocultar esta tarea personalizada? El historial de visitas se conserva.';
    if(!confirm(message))return;
    setSyncState('saving');
    const{error}=await sb.rpc('remove_project_check_item_config',{p_id:recordId});
    if(error){setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}
    await loadOperationalData();closeModal();setSyncState('saved');taskManager(project(p.id),s.id);toast(sourceItemId?'Tarea original restaurada':'Tarea ocultada')
  };
}

function stageConfig(p){modal('Etapas habilitadas',groupedStageCheckboxes(p.enabledStages),`<button class="ghost" data-close>Cancelar</button><button class="solid" id="saveStages">Guardar</button>`);$('#saveStages').onclick=async()=>{const button=$('#saveStages'),enabledStages=$$('input[type=checkbox]:checked').map(x=>x.value);if(!enabledStages.length)return toast('Habilitá al menos una etapa');button.disabled=true;button.textContent='Guardando…';setSyncState('saving');const{error}=await sb.from('projects').update({enabled_stages:enabledStages,updated_at:new Date().toISOString()}).eq('id',p.id);if(error){button.disabled=false;button.textContent='Guardar';setSyncState('error',dbErrorText(error));return toast(dbErrorText(error))}p.enabledStages=enabledStages;save();closeModal();setSyncState('saved');render();toast('Etapas sincronizadas')}}
function search(q){q=q.trim().toLowerCase();const r=$('#searchResults');if(!q){r.innerHTML=empty('Ingresá un término de búsqueda.');return}const iss=state.issues.filter(i=>[i.code,i.title,i.note,i.contactName,i.sector].join(' ').toLowerCase().includes(q)),ps=state.projects.filter(p=>[p.name,p.client,p.location,p.status].join(' ').toLowerCase().includes(q)),cs=[];for(const p of state.projects)for(const s of stages.filter(x=>p.enabledStages.includes(x.id)))for(const it of taskItems(p,s))if([it.task,it.future,s.name].join(' ').toLowerCase().includes(q))cs.push({p,s,it});r.innerHTML=[...ps.map(projectRow),...iss.map(issueRow),...cs.slice(0,20).map(x=>`<button class="row" data-project="${x.p.id}"><span class="dot"></span><div class="row-main"><div class="row-title">${esc(x.it.task)}</div><div class="row-sub">${esc(x.p.name)} · ${esc(x.s.name)}</div></div>${ico('next')}</button>`)].join('')||empty('No se encontraron resultados.');$$('[data-project]',r).forEach(b=>b.onclick=()=>go({view:'project',projectId:b.dataset.project}));$$('[data-issue]',r).forEach(b=>b.onclick=()=>issueModal(b.dataset.issue))}
