function projectTypesModal(){const list=[...(state.projectTypes||defaultProjectTypes)].sort((a,b)=>a.name.localeCompare(b.name,'es'));modal('Tipos de proyecto',`<div class="list">${list.map(x=>`<button class="row" data-edit-project-type="${x.id}"><div class="row-main"><div class="row-title">${esc(x.name)}</div><div class="row-sub">${x.sectorNames.length} sectores · ${x.enabledStageIds.length} etapas habilitadas${x.active===false?" · Desactivado":""}</div></div>${ico('next')}</button>`).join('')||empty('No hay tipos configurados.')}</div>`,`<button class="ghost" data-close>Cerrar</button><button class="solid" id="newProjectType">${ico('plus')} Agregar tipo</button>`);$$('[data-edit-project-type]').forEach(b=>b.onclick=()=>projectTypeForm(list.find(x=>x.id===b.dataset.editProjectType)));$('#newProjectType').onclick=()=>projectTypeForm()}
