async function initAuth(){try{const{data:{session},error}=await sb.auth.getSession();if(error)throw error;currentSession=session;if(session)await loadRemoteWorkspace()}catch(error){authMessage=dbErrorText(error);workspaceError=authMessage}finally{authReady=true;render()}sb.auth.onAuthStateChange((event,session)=>{currentSession=session;if(event==='SIGNED_OUT'){currentProfile=null;state.projects=[];workspaceError='';save();route={view:'home'};setTimeout(()=>render(),0)}else if(session&&(event==='SIGNED_IN'||event==='TOKEN_REFRESHED'||event==='INITIAL_SESSION'))setTimeout(async()=>{try{await loadRemoteWorkspace()}catch(error){workspaceError=dbErrorText(error)}authReady=true;render()},0)})}
async function refreshRemote(){if(syncing)return;syncing=true;render();try{await loadRemoteWorkspace();toast('Datos actualizados')}catch(error){workspaceError=dbErrorText(error);toast(workspaceError)}finally{syncing=false;render()}}

async function loadAppConfiguration(){const[typeResult,groupResult]=await Promise.all([sb.from('project_types').select('id,name,sector_names,enabled_stage_ids,is_active').order('name'),sb.from('stage_groups').select('id,name,sort_order,stage_ids,is_active').order('sort_order')]);if(typeResult.error)throw typeResult.error;if(groupResult.error)throw groupResult.error;state.projectTypes=(typeResult.data||[]).map(x=>({id:x.id,name:x.name,sectorNames:Array.isArray(x.sector_names)?x.sector_names:['General'],enabledStageIds:Array.isArray(x.enabled_stage_ids)?x.enabled_stage_ids:stages.map(s=>s.id),active:x.is_active}));state.stageGroups=(groupResult.data||[]).map(x=>({id:x.id,name:x.name,sortOrder:x.sort_order,stageIds:Array.isArray(x.stage_ids)?x.stage_ids:[],active:x.is_active}));if(!state.projectTypes.length)state.projectTypes=[...defaultProjectTypes];if(!state.stageGroups.length)state.stageGroups=[...defaultStageGroups];save()}

async function loadRemoteWorkspace(){if(!currentSession)return;syncing=true;const uid=currentSession.user.id;const{data:profileData,error:profileError}=await sb.from('profiles').select('id,full_name,app_role').eq('id',uid).maybeSingle();if(profileError)throw profileError;if(!profileData)throw new Error('No existe el perfil del usuario.');currentProfile=profileData;state.user={id:uid,name:profileData.full_name||currentSession.user.email,role:profileData.app_role};await loadAppConfiguration();const{data:rows,error}=await sb.rpc('get_my_projects');if(error)throw error;state.projects=(rows||[]).map(r=>({id:r.project_id,name:r.project_name,client:r.client||'',location:r.location||'',template:r.template||'Vivienda',status:r.project_status||'En ejecución',currentStage:r.current_stage||'preobra',enabledStages:Array.isArray(r.enabled_stages)&&r.enabled_stages.length?r.enabled_stages:stages.map(s=>s.id),projectRole:r.member_role||'read_only',sectors:Array.isArray(r.sectors)&&r.sectors.length?r.sectors.map(s=>s.name):['General'],sectorRecords:Array.isArray(r.sectors)?r.sectors:[],contacts:Array.isArray(r.contacts)?r.contacts.map(c=>({id:c.id,name:c.name,trade:c.trade||'',phone:c.phone||'',email:c.email||''})):[],members:project(r.project_id)?.members||[],createdAt:r.created_at}));await loadOperationalData();lastSync=new Date().toISOString();workspaceError='';syncing=false;save();setSyncState('saved')}
async function loadOperationalData(){if(!currentSession)return;const{data,error}=await sb.rpc('get_my_operational_data');if(error)throw error;const d=data||{};state.visits=(d.visits||[]).map(v=>({id:v.id,projectId:v.project_id,stageId:v.stage_id,sector:v.sector_name,startedAt:v.started_at,endedAt:v.ended_at,status:v.status||'closed',userId:v.performed_by,userName:v.user_name,reviewed:v.reviewed_count||0,issues:v.issue_count||0,ok:v.conforming_count||0,plannedVisitId:v.planned_visit_id,filter:'all',query:''}));state.plannedVisits=(d.planned_visits||[]).map(v=>({id:v.id,projectId:v.project_id,stageId:v.stage_id,sector:v.sector_name,date:v.planned_date,time:v.planned_time?String(v.planned_time).slice(0,5):'',assignee:v.assignee_name||state.user.name,note:v.objective||'',status:v.status,createdAt:v.created_at,updatedAt:v.updated_at}));state.checks={};for(const c of d.current_checks||[])state.checks[key(c.project_id,c.stage_id,c.sector_name,c.check_item_id)]={status:c.status,note:c.note||'',contactId:c.contact_id,dueDate:c.due_date,visitId:c.visit_id,updatedAt:c.updated_at};state.visitResults={};for(const c of d.visit_results||[])state.visitResults[visitKey(c.visit_id,c.sector_name,c.check_item_id)]={status:c.status,note:c.note||'',contactId:c.contact_id,dueDate:c.due_date,visitId:c.visit_id,sector:c.sector_name,itemId:c.check_item_id,title:c.title||'',priority:c.priority||'Media',createdAt:c.created_at,updatedAt:c.updated_at};state.projectTasks=(d.project_tasks||[]).map(t=>({id:t.id,projectId:t.project_id,stageId:t.stage_id,itemKey:t.item_key,sourceItemId:t.source_item_id,task:t.task,future:t.future||'',priority:t.priority||'Media',blocks:!!t.blocks,sortOrder:t.sort_order||0,active:t.is_active!==false,createdAt:t.created_at,updatedAt:t.updated_at}));state.issues=(d.issues||[]).map(i=>({id:i.id,code:i.code,projectId:i.project_id,stageId:i.stage_id,sector:i.sector_name,itemId:i.check_item_id,title:i.title,status:i.status,priority:i.priority,note:i.note||'',contactId:i.contact_id,contactName:i.contact_name||'',dueDate:i.due_date,lifecycle:i.lifecycle,visitId:i.visit_id,createdAt:i.created_at,updatedAt:i.updated_at}));const drafts=state.visits.filter(v=>v.status==='draft'&&v.userId===currentSession.user.id);state.activeVisit=state.activeVisit&&state.visits.some(v=>v.id===state.activeVisit.id)?state.visits.find(v=>v.id===state.activeVisit.id):(drafts[0]||null);visit=state.activeVisit;save()}
function dbErrorText(error){const message=error?.message||String(error||'Error desconocido'),m=message.toLowerCase();if(m.includes('save_project_check_item')||m.includes('remove_project_check_item_config')||m.includes('project_check_items'))return'Falta ejecutar la migración v7 de tareas personalizadas.';if(m.includes('resolve_issue_as_conforming'))return'Falta ejecutar la migración v6.';if(m.includes('save_project_type_config')||m.includes('save_stage_group_config')||m.includes('mark_visit_check_bad_all_sectors'))return'Falta ejecutar la migración v5.';if(m.includes('project_types')||m.includes('stage_groups')||m.includes('save_visit_check_v2')||m.includes('mark_visit_check_ok_all_sectors'))return'Falta ejecutar la migración v4 de etapas y tipos de proyecto.';if(m.includes('get_my_operational_data')||m.includes('create_visit_draft'))return'Falta ejecutar la migración operativa v3.';if(m.includes('row-level security'))return'La política de acceso bloqueó esta operación.';if(m.includes('no existe un usuario')||m.includes('user_not_found'))return'No existe un usuario con ese correo.';if(m.includes('duplicate key'))return'Ya existe un registro con esos datos.';if(m.includes('failed to fetch'))return'No se pudo conectar. Revisá la conexión a internet.';return message}

